void mergeArrays(int a[], int b[], int c[], int n1, int n2) {
    int i, j;
    for (i = 0; i < n1; i++)
        c[i] = a[i];
    for (j = 0; j < n2; j++)
        c[n1 + j] = b[j];
}

int main() {
    int arr1[3] = {1, 2, 3}, arr2[3] = {4, 5, 6};
