        printf("%d ", merged[i]);

    return 0;
}

#include <stdio.h>

int sumArray(int *ptr, int n) {
    int sum = 0;
    int i;
    for (i = 0; i < n; i++)
        sum = sum + *(ptr + i);
    return sum;
}

int main() {
    int arr[4] = {10, 20, 30, 40};
    int *p;
    int result;

    p = arr;
    result = sumArray(p, 4);

    printf("Sum = %d", result);
    return 0;
}

#include <stdio.h>

int matrixSum(int mat[2][3], int rows, int cols) {
    int sum = 0;
    int i, j;
    for (i = 0; i < rows; i++)
        for (j = 0; j < cols; j++)
            sum = sum + mat[i][j];
    return sum;
}

int main() {
    int matrix[2][3] = {{1, 2, 3}, {4, 5, 6}};
    int result;
    int i, j;

    result = matrixSum(matrix, 2, 3);

    printf("Matrix Sum = %d", result);
    return 0;
}

#include <stdio.h>

void transpose(int (*src)[3], int (*dest)[2], int rows, int cols) {
    int i, j;
    for (i = 0; i < rows; i++)
        for (j = 0; j < cols; j++)
            dest[j][i] = src[i][j];
}

int main() {
    int matrix[2][3] = {{1, 2, 3}, {4, 5, 6}};
    int result[3][2];
    int i, j;

    transpose(matrix, result, 2, 3);

    printf("Transposed:\n");
    for (i = 0; i < 3; i++) {
        for (j = 0; j < 2; j++)
            printf("%d ", result[i][j]);
        printf("\n");
    }
    return 0;
}
